import { readFileSync, writeFileSync, renameSync, existsSync, unlinkSync, lstatSync, mkdirSync, chmodSync, } from "node:fs";
import { join, dirname, sep } from "node:path";
import { fileURLToPath } from "node:url";
import { homedir } from "node:os";
import { loadConfig, saveConfig } from "./config.js";
// Re-run the statusline command on a fixed timer so Codex "resets in Xm"
// countdowns stay current while the main session is idle (Claude Code v2.1.97+).
const REFRESH_INTERVAL_SECONDS = 60;
function getClaudeDir() {
    return process.env["CLAUDE_CONFIG_DIR"] || join(homedir(), ".claude");
}
function getLauncherPath() {
    return join(getClaudeDir(), "codex-hud-statusline.sh");
}
function getSettingsPath() {
    return join(getClaudeDir(), "settings.json");
}
function getWrapperPath() {
    // CLAUDE_PLUGIN_ROOT is set by Claude Code when running plugin commands
    const pluginRoot = process.env["CLAUDE_PLUGIN_ROOT"];
    if (pluginRoot) {
        return join(pluginRoot, "scripts", "statusline-wrapper.sh");
    }
    // Fallback: derive from this script's location (dist/install-statusline.js -> ../scripts/...)
    try {
        const here = dirname(fileURLToPath(import.meta.url));
        return join(here, "..", "scripts", "statusline-wrapper.sh");
    }
    catch {
        return null;
    }
}
function shellQuote(s) {
    return `'${s.replace(/'/g, `'\\''`)}'`;
}
// The launcher is a real script (not a symlink): marketplace installs live in
// a VERSION-NUMBERED cache dir (~/.claude/plugins/cache/<mp>/codex-hud/<ver>/),
// so a symlink would dangle (or pin a stale version) on every /plugin update.
// Instead, resolve the current install at runtime:
//   - installed_plugins.json installPath (authoritative)
//   - newest versioned cache dir under any marketplace alias
//   - the install-time path (tried FIRST for dev-tree installs so local
//     development keeps using the working tree, LAST for cache installs so
//     a stale versioned dir can never shadow an update).
function buildLauncher(wrapperPath, claudeDir) {
    const cachePrefix = join(claudeDir, "plugins", "cache") + sep;
    const isCacheInstall = wrapperPath.startsWith(cachePrefix);
    const quotedWrapper = shellQuote(wrapperPath);
    const tryInstallTime = `try_wrapper ${quotedWrapper}`;
    return `#!/bin/bash
# codex-hud statusline launcher (generated by /codex-hud:setup).
# Resolves the current codex-hud install at runtime so /plugin update
# never leaves the statusline pointing at a removed versioned cache dir.
CFG="\${CLAUDE_CONFIG_DIR:-$HOME/.claude}"

try_wrapper() { [ -f "$1" ] && exec /bin/bash "$1"; }
${isCacheInstall ? "" : `\n# Dev-tree install: prefer the working tree while it exists.\n${tryInstallTime}\n`}
# Authoritative: installPath from Claude Code's plugin metadata.
META="$CFG/plugins/installed_plugins.json"
NODE_BIN="$(command -v node)"
if [ -f "$META" ] && [ -n "$NODE_BIN" ]; then
  P="$("$NODE_BIN" -e '
    try {
      const data = JSON.parse(require("fs").readFileSync(process.argv[1], "utf-8"));
      for (const [key, entries] of Object.entries(data.plugins || {})) {
        if (!key.startsWith("codex-hud@")) continue;
        for (const e of entries || []) {
          if (e && e.installPath) { console.log(e.installPath); process.exit(0); }
        }
      }
    } catch {}
  ' "$META" 2>/dev/null)"
  [ -n "$P" ] && try_wrapper "$P/scripts/statusline-wrapper.sh"
fi

# Fallback: newest versioned cache dir under any marketplace alias.
LATEST="$(ls -td "$CFG"/plugins/cache/*/codex-hud/*/ 2>/dev/null | head -1)"
[ -n "$LATEST" ] && try_wrapper "\${LATEST}scripts/statusline-wrapper.sh"
${isCacheInstall ? `\n# Last resort: the path recorded at install time.\n${tryInstallTime}\n` : ""}
echo "codex-hud: install not found — run /codex-hud:setup"
`;
}
// Crash-mid-write on ~/.claude/settings.json would corrupt the user's entire
// global Claude Code settings; write to a temp file and rename into place.
function writeFileAtomic(path, content) {
    const tmp = `${path}.tmp.${process.pid}`;
    writeFileSync(tmp, content);
    renameSync(tmp, path);
}
function removeExisting(path) {
    try {
        // Covers regular files AND symlinks (including dangling ones, where
        // existsSync is false but the link itself still occupies the path).
        // Never write through a pre-existing symlink: it would hit the target.
        if (lstatSync(path, { throwIfNoEntry: false })) {
            unlinkSync(path);
        }
    }
    catch {
        // ignore
    }
}
function installLauncher(wrapperPath) {
    const launcherPath = getLauncherPath();
    const dir = dirname(launcherPath);
    if (!existsSync(dir)) {
        mkdirSync(dir, { recursive: true });
    }
    try {
        removeExisting(launcherPath);
        writeFileSync(launcherPath, buildLauncher(wrapperPath, getClaudeDir()), {
            mode: 0o755,
        });
        chmodSync(launcherPath, 0o755);
        return { created: true, error: null };
    }
    catch (err) {
        return {
            created: false,
            error: err instanceof Error ? err.message : String(err),
        };
    }
}
function updateSettings() {
    const settingsPath = getSettingsPath();
    const launcherPath = getLauncherPath();
    let settings = {};
    if (existsSync(settingsPath)) {
        try {
            const raw = readFileSync(settingsPath, "utf-8");
            settings = JSON.parse(raw);
        }
        catch (err) {
            return {
                updated: false,
                previous: null,
                savedPrevious: false,
                error: `Could not parse ${settingsPath}: ${err instanceof Error ? err.message : String(err)}`,
            };
        }
    }
    const current = settings["statusLine"];
    const currentCommand = typeof current?.["command"] === "string"
        ? current["command"]
        : null;
    // Already fully configured -> nothing to do.
    if (currentCommand === launcherPath &&
        current?.["refreshInterval"] === REFRESH_INTERVAL_SECONDS) {
        return {
            updated: false,
            previous: currentCommand,
            savedPrevious: false,
            error: null,
        };
    }
    // Remember the user's own statusline (not a previous codex-hud install)
    // so uninstall can put it back.
    let savedPrevious = false;
    if (current && currentCommand !== launcherPath) {
        saveConfig({ ...loadConfig(), previousStatusLine: current });
        savedPrevious = true;
    }
    // Merge rather than replace: preserve unknown fields like `padding`.
    settings["statusLine"] = {
        ...(current ?? {}),
        type: "command",
        command: launcherPath,
        refreshInterval: REFRESH_INTERVAL_SECONDS,
    };
    try {
        writeFileAtomic(settingsPath, JSON.stringify(settings, null, 2) + "\n");
        return { updated: true, previous: currentCommand, savedPrevious, error: null };
    }
    catch (err) {
        return {
            updated: false,
            previous: currentCommand,
            savedPrevious,
            error: err instanceof Error ? err.message : String(err),
        };
    }
}
export function installStatusline() {
    const wrapperPath = getWrapperPath();
    if (!wrapperPath || !existsSync(wrapperPath)) {
        return {
            ok: false,
            launcherCreated: false,
            settingsUpdated: false,
            previousCommand: null,
            message: `Could not locate statusline wrapper script at ${wrapperPath ?? "unknown path"}. Make sure CLAUDE_PLUGIN_ROOT is set.`,
        };
    }
    const launcher = installLauncher(wrapperPath);
    if (!launcher.created) {
        return {
            ok: false,
            launcherCreated: false,
            settingsUpdated: false,
            previousCommand: null,
            message: `Failed to write launcher at ${getLauncherPath()}: ${launcher.error}`,
        };
    }
    const upd = updateSettings();
    if (upd.error) {
        return {
            ok: false,
            launcherCreated: true,
            settingsUpdated: false,
            previousCommand: upd.previous,
            message: `Launcher created but settings.json update failed: ${upd.error}`,
        };
    }
    const parts = [
        `Launcher: ${getLauncherPath()} (resolves the current install at runtime)`,
        upd.updated
            ? upd.savedPrevious
                ? `Updated ~/.claude/settings.json (previous statusline saved for uninstall: ${upd.previous})`
                : `Updated ~/.claude/settings.json statusLine`
            : `~/.claude/settings.json already points to the launcher, no change`,
        "",
        "Restart Claude Code or run /reload-plugins to see the Codex statusline.",
    ];
    return {
        ok: true,
        launcherCreated: true,
        settingsUpdated: upd.updated,
        previousCommand: upd.previous,
        message: parts.join("\n"),
    };
}
export function uninstallStatusline() {
    const launcherPath = getLauncherPath();
    const settingsPath = getSettingsPath();
    const messages = [];
    try {
        if (lstatSync(launcherPath, { throwIfNoEntry: false })) {
            unlinkSync(launcherPath);
            messages.push(`Removed launcher: ${launcherPath}`);
        }
    }
    catch {
        // ignore
    }
    if (existsSync(settingsPath)) {
        try {
            const raw = readFileSync(settingsPath, "utf-8");
            const settings = JSON.parse(raw);
            const sl = settings["statusLine"];
            if (sl?.command === launcherPath) {
                const config = loadConfig();
                if (config.previousStatusLine) {
                    settings["statusLine"] = config.previousStatusLine;
                    messages.push("Restored your previous statusline in ~/.claude/settings.json");
                    const { previousStatusLine: _drop, ...rest } = config;
                    void _drop;
                    saveConfig(rest);
                }
                else {
                    delete settings["statusLine"];
                    messages.push("Cleared statusLine from ~/.claude/settings.json");
                }
                writeFileAtomic(settingsPath, JSON.stringify(settings, null, 2) + "\n");
            }
        }
        catch {
            messages.push("Could not update settings.json (skipped)");
        }
    }
    if (messages.length === 0) {
        messages.push("Nothing to uninstall.");
    }
    return { ok: true, message: messages.join("\n") };
}
